-- Generated by build_plan_year.py — latest congressional plan year per state
-- (from the DRA block-assignment filenames = the map currently in effect).
UPDATE puzzles p SET census = census || jsonb_build_object('planYear', n.yr)
FROM (VALUES
  ('AL',2024),
  ('AR',2022),
  ('AZ',2022),
  ('CA',2026),
  ('CO',2022),
  ('CT',2022),
  ('FL',2026),
  ('GA',2024),
  ('HI',2022),
  ('IA',2022),
  ('ID',2022),
  ('IL',2022),
  ('IN',2022),
  ('KS',2022),
  ('KY',2022),
  ('LA',2026),
  ('MA',2022),
  ('MD',2022),
  ('ME',2022),
  ('MI',2022),
  ('MN',2022),
  ('MO',2026),
  ('MS',2022),
  ('MT',2022),
  ('NC',2026),
  ('NE',2022),
  ('NH',2022),
  ('NJ',2022),
  ('NM',2022),
  ('NV',2022),
  ('NY',2024),
  ('OH',2026),
  ('OK',2022),
  ('OR',2022),
  ('PA',2022),
  ('RI',2022),
  ('SC',2022),
  ('TN',2026),
  ('TX',2026),
  ('UT',2026),
  ('VA',2022),
  ('WA',2022),
  ('WI',2022),
  ('WV',2022)
) AS n(state, yr)
WHERE p.state = n.state;
